import { useEffect, useState } from 'react';
import { MapPin, Mail, Github, Linkedin } from 'lucide-react';

const phrases = ['Cybersecurity Enthusiast','AI & Gen AI Practitioner','Web Developer','Network Enthusiast','MIS Student'];

export default function Hero() {
  const [text, setText] = useState('');
  const [pi, setPi] = useState(0);
  const [ci, setCi] = useState(0);
  const [del, setDel] = useState(false);

  useEffect(() => {
    const phrase = phrases[pi];
    const t = setTimeout(() => {
      if (!del) {
        setText(phrase.slice(0, ci + 1));
        if (ci + 1 === phrase.length) { setTimeout(() => setDel(true), 1600); return; }
        setCi(c => c + 1);
      } else {
        setText(phrase.slice(0, ci - 1));
        if (ci - 1 === 0) { setDel(false); setPi(p => (p + 1) % phrases.length); setCi(0); return; }
        setCi(c => c - 1);
      }
    }, del ? 45 : 90);
    return () => clearTimeout(t);
  }, [ci, pi, del]);

  return (
    <section id="hero" className="min-h-screen bg-parchment grid md:grid-cols-2 items-center gap-8 px-[5%] relative overflow-hidden">
      <div className="blob-hero w-[520px] h-[520px] bg-amber opacity-10 top-[-80px] right-[-100px]" />
      <div className="blob-hero-2 w-[240px] h-[240px] bg-teal opacity-[0.07] bottom-[-30px] left-[35%]" />

      <div className="relative z-10 pt-24 pb-10 md:pb-0 md:pt-0">
        <span className="inline-flex items-center gap-1.5 text-xs font-semibold tracking-widest uppercase text-amber mb-4">
          <MapPin size={12} /> Asyut, Egypt
        </span>
        <p className="text-lg text-muted2 mb-1">Hi, I'm</p>
        <h1 className="font-serif-display text-5xl md:text-7xl leading-[1.05] tracking-tight">
          Kareem<br /><em className="text-amber not-italic font-serif-display">Basem Fathi.</em>
        </h1>
        <div className="flex items-center gap-2 mt-5 text-sm font-medium">
          <span className="text-amber font-bold">→</span>
          <span className="text-ink font-semibold">{text}</span>
          <span className="text-amber animate-[ping2_1s_step-end_infinite]">|</span>
        </div>
        <p className="mt-4 text-[0.95rem] leading-[1.8] text-muted2 max-w-[440px]">
          I'm a <strong className="text-ink2 font-semibold">Management Information Systems</strong> student at Sadat Academy.
          I have practical experience and I'm always working on projects that help me learn and improve.
          Passionate about <strong className="text-ink2 font-semibold">Cybersecurity, AI, Networks & Web Development</strong>.
        </p>
        <div className="flex gap-3 flex-wrap mt-7">
          <a href="#projects" className="px-6 py-3 bg-ink text-parchment font-semibold text-sm rounded-full transition-all hover:bg-amber hover:-translate-y-1 hover:shadow-[0_8px_24px_rgba(240,165,0,.28)]">View My Work</a>
          <a href="#contact" className="px-6 py-3 border-[1.5px] border-ink/20 text-ink2 font-semibold text-sm rounded-full transition-all hover:border-amber hover:text-amber hover:-translate-y-1">Get In Touch</a>
        </div>
        <div className="flex items-center gap-3 mt-7">
          <span className="text-xs uppercase tracking-wider text-muted">Find me</span>
          {[
            { href:'https://www.linkedin.com/in/karem-basem', icon:<Linkedin size={14}/> },
            { href:'https://github.com/Kareem-Basem', icon:<Github size={14}/> },
            { href:'mailto:karemalwy1@gmail.com', icon:<Mail size={14}/> },
          ].map((s,i) => (
            <a key={i} href={s.href} target={s.href.startsWith('http')?'_blank':undefined} rel="noreferrer"
              className="w-9 h-9 rounded-full border-[1.5px] border-ink/12 flex items-center justify-center text-muted2 transition-all hover:border-amber hover:text-amber hover:-translate-y-0.5">
              {s.icon}
            </a>
          ))}
        </div>
      </div>

      <div className="hidden md:flex flex-col items-center gap-5 relative z-10">
        <div className="relative w-[300px] h-[300px] float">
          <div className="blob-avatar absolute inset-0 bg-gradient-to-br from-amber to-[#ffd166]" />
          <div className="absolute inset-[22px] rounded-full bg-cream2 flex items-center justify-center shadow-inner overflow-hidden">
            {/* بعد ما تبعت صورتك: استبدل السطر ده بـ <img src="/photo.jpg" alt="Kareem" className="w-full h-full object-cover" /> */}
            <span className="font-serif-display text-[4rem] italic text-ink2">KB</span>
          </div>
          <div className="absolute top-4 -right-4 bg-parchment rounded-2xl px-3 py-2 shadow-[0_8px_32px_rgba(26,26,46,.11)] flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500 ping2 block" />
            <div><div className="text-[0.78rem] font-semibold text-ink">Open to Work</div><div className="text-[0.65rem] text-muted">Available now</div></div>
          </div>
          <div className="absolute bottom-8 -left-6 bg-parchment rounded-2xl px-3 py-2 shadow-[0_8px_32px_rgba(26,26,46,.11)] flex items-center gap-2">
            <span className="font-serif-display text-2xl italic text-teal">15+</span>
            <div className="text-[0.65rem] text-muted leading-tight">Certifications<br/>earned</div>
          </div>
        </div>
      </div>
    </section>
  );
}
